{"path": "/data/agents/aton/projects/roast-or-toast/src/index.ts", "content": "import { Hono } from "hono";
import { registerSnapHandler } from "@farcaster/snap-hono";

const app = new Hono();

// ─── Config ───────────────────────────────────────────────────────
const NEYNAR_API_KEY = process.env.NEYNAR_API_KEY || "";
const SNAP_BASE = process.env.SNAP_PUBLIC_BASE_URL || "https://roast-or-toast.host.neynar.app";

// ─── Roast Templates ─────────────────────────────────────────────
const roastTemplates = [
  (p: any) => {
    const c = p.follower_count;
    if (c > 100000) return `@${p.username} with ${formatNum(c)} followers... that's ${formatNum(c)} people who forgot to unfollow.`;
    if (c > 10000) return `@${p.username} really said "I'm building in public" and then just posted vibes for ${formatNum(c)} followers.`;
    if (c > 1000) return `${formatNum(c)} followers and @${p.username} still checks if the influencer followed back. They didn't.`;
    if (c < 50) return `@${p.username} has ${c} followers. That's not a following, that's a group chat.`;
    return `@${p.username} has ${formatNum(c)} followers and somehow ${formatNum(p.following_count)} following. Bro collects follows like pokemon cards.`;
  },
  (p: any) => {
    const b = (p.bio || "").trim();
    if (!b) return `@${p.username} has no bio. Even their profile gave up.`;
    if (b.length < 20) return `@${p.username}'s entire personality in ${b.length} characters: "${b}"`;
    if (b.toLowerCase().includes("builder")) return `@${p.username} calls themselves a "builder" but their pinned cast is a meme.`;
    if (b.toLowerCase().includes("degen")) return `@${p.username} proudly calls themselves a degen. At least they're self-aware.`;
    if (b.toLowerCase().includes("web3")) return `@${p.username} put "web3" in their bio like it's 2021. Sir, the bear market is RIGHT THERE.`;
    return `@${p.username}'s bio: "${b.substring(0, 60)}..." — ChatGPT definitely wrote this.`;
  },
  (p: any) => {
    const ratio = p.following_count / Math.max(p.follower_count, 1);
    if (ratio > 10) return `@${p.username} follows ${formatNum(p.following_count)} people but only ${formatNum(p.follower_count)} follow back. Ratio so bad it's clinical.`;
    if (ratio < 0.1) return `@${p.username} follows ${formatNum(p.following_count)} people. "I just like keeping up with friends." Sure.`;
    if (p.power_badge) return `@${p.username} has a power badge. So did MySpace Tom and look how that turned out.`;
    return `@${p.username} — follower ratio: ${ratio.toFixed(1)}. Not great, not terrible. Mostly terrible.`;
  },
  (p: any) => {
    const reg = new Date(p.registered_at).getFullYear();
    if (reg <= 2022) return `@${p.username} joined in ${reg} and STILL hasn't figured out threads. Boomer energy.`;
    if (reg >= 2025) return `@${p.username} joined in ${reg}. Welcome! You missed the golden age. It's all downhill from here.`;
    return `@${p.username} joined Farcaster in ${reg}. Congrats on discovering the internet's most expensive group chat.`;
  },
  (p: any) => {
    const n = p.display_name || p.username;
    const roasts = [
      `${n}? More like ${n.toLowerCase()}t interesting.`,
      `I asked ChatGPT to describe ${n} and it said "insufficient data."`,
      `${n} peaked in ${Math.floor(Math.random() * 3) + 2022}.`,
      `${n} is proof that verification doesn't mean verified quality.`,
      `If ${n} was a token, they'd be a stablecoin. Boring and flat.`
    ];
    return roasts[Math.floor(Math.random() * roasts.length)];
  }
];

// ─── Toast Templates ─────────────────────────────────────────────
const toastTemplates = [
  (p: any) => {
    const c = p.follower_count;
    if (c > 100000) return `${formatNum(c)} followers. @${p.username} built something real. Respect.`;
    if (c > 10000) return `@${p.username} grew to ${formatNum(c)} followers because they actually ship. Unlike the rest of us.`;
    if (c > 1000) return `@${p.username} has ${formatNum(c)} followers who actually engage. That's rarer than a green portfolio.`;
    if (c < 50) return `@${p.username} has ${c} followers and still shows up every day. That's real conviction. Legend.`;
    return `@${p.username} — ${formatNum(c)} followers, ${formatNum(p.following_count)} following. Perfectly balanced.`;
  },
  (p: any) => {
    const b = (p.bio || "").trim();
    if (!b) return `@${p.username} doesn't need a bio. Their casts speak for themselves.`;
    if (b.toLowerCase().includes("builder")) return `@${p.username} says "builder" in their bio and actually builds. That's rare.`;
    if (b.toLowerCase().includes("art")) return `@${p.username} makes art in a space full of grifters. We need more of this.`;
    return `@${p.username} bio game is strong. "${b.substring(0, 50)}..." — chef's kiss.`;
  },
  (p: any) => {
    const toasts = [
      `@${p.username} is the kind of person who replies to threads instead of just liking. Real one.`,
      `@${p.username} shows up in your feed and you actually stop scrolling. That's power.`,
      `If @${p.username} left Farcaster, the vibes would noticeably drop.`,
      `@${p.username} is what happens when someone genuinely cares about the community.`,
      `@${p.username} is the friend who remembers your wins. Keep that energy.`
    ];
    return toasts[Math.floor(Math.random() * toasts.length)];
  },
  (p: any) => {
    const n = p.display_name || p.username;
    const toasts = [
      `${n} — the main character energy we all pretend we don't want.`,
      `${n} is the person your mutuals tell you to follow. They were right.`,
      `${n} doesn't just touch grass. They plant it. Respect.`,
      `${n} makes Farcaster feel like the internet used to. That's a compliment.`,
      `${n} is the kind of account that makes you stay on this app.`
    ];
    return toasts[Math.floor(Math.random() * toasts.length)];
  }
];

// ─── Utils ────────────────────────────────────────────────────────
function formatNum(n: number): string {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + "M";
  if (n >= 1000) return (n / 1000).toFixed(1) + "K";
  return String(n);
}

function getInitials(p: any): string {
  const name = p.display_name || p.username || "?";
  return name.split(/\s+/).map((w: string) => w[0]).join("").toUpperCase().slice(0, 2) || "?";
}

function safeImageUrl(url: string | null | undefined, username: string): string {
  if (!url) return `https://dummyimage.com/120x120/1a1625/9b87f5.png&text=${encodeURIComponent(username[0]?.toUpperCase() || "?")}`;
  try {
    const u = new URL(url);
    const ext = u.pathname.split(".").pop()?.toLowerCase();
    if (["jpg", "jpeg", "png", "gif", "webp"].includes(ext || "")) return url;
    if (u.hostname.includes("imagedelivery.net")) return `https://dummyimage.com/120x120/1a1625/9b87f5.png&text=${encodeURIComponent(username[0]?.toUpperCase() || "?")}`;
    return `https://dummyimage.com/120x120/1a1625/9b87f5.png&text=${encodeURIComponent(username[0]?.toUpperCase() || "?")}`;
  } catch {
    return `https://dummyimage.com/120x120/1a1625/9b87f5.png&text=${encodeURIComponent(username[0]?.toUpperCase() || "?")}`;
  }
}

function generateRoast(p: any): string {
  return roastTemplates[Math.floor(Math.random() * roastTemplates.length)](p);
}

function generateToast(p: any): string {
  return toastTemplates[Math.floor(Math.random() * toastTemplates.length)](p);
}

// ─── Neynar API ───────────────────────────────────────────────────
async function fetchRandomProfile(myFid: number): Promise<any | null> {
  const offset = Math.floor(Math.random() * 100);
  const url = `https://snapchain-api.neynar.com/v2/farcaster/cast?fid=${myFid}&type=casts&limit=25&offset=${offset}`;
  try {
    const resp = await fetch(url, { headers: { "x-api-key": NEYNAR_API_KEY } });
    if (!resp.ok) return null;
    const data = await resp.json();
    const fids = [...new Set(data.messages?.map((m: any) => m.data?.fid).filter((f: number) => f && f !== myFid) || [])];
    if (fids.length === 0) return null;
    const targetFid = fids[Math.floor(Math.random() * fids.length)] as number;
    const resp2 = await fetch(
      `https://api.neynar.com/v2/farcaster/user/bulk?fids=${targetFid}`,
      { headers: { "x-api-key": NEYNAR_API_KEY, "accept": "application/json" } }
    );
    if (!resp2.ok) return null;
    const data2 = await resp2.json();
    return data2.users?.[0] || null;
  } catch { return null; }
}

// ─── Route Handlers ───────────────────────────────────────────────

// Initial card — purple gradient, BIG text, invite to play
registerSnapHandler(app, {
  handler: () => ({
    type: "frame",
    frame: {
      title: "ROAST OR TOAST",
      image: {
        src: `${SNAP_BASE}/initial`,
        aspectRatio: "3:2"
      },
      buttons: [
        { label: "GET TARGET", icon: "arrow-right" },
        { label: "HOW IT WORKS" }
      ],
      input: { text: "" },
      postUrl: `${SNAP_BASE}/get-target`
    },
    theme: {
      accent: "#9b87f5",
      background: "#0f0b1a",
      foreground: "#e8e0f0"
    }
  }),
  fallbackHtml: `<html><head><meta name="snap-theme" content="dark"><style>*{margin:0;padding:0;box-sizing:border-box}body{background:#0f0b1a;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0}</style></head><body>ROAST OR TOAST</body></html>`
});

app.get("/initial", (c) => {
  return c.html(`<!DOCTYPE html><html><head><style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:linear-gradient(135deg,#0f0b1a,#1a1025,#0f0b1a);display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0}
    .wrap{text-align:center}
    .emoji{font-size:80px;margin-bottom:16px}
    h1{font-size:52px;font-weight:900;background:linear-gradient(135deg,#9b87f5,#d946ef);-webkit-background-clip:text;-webkit-text-fill-color:transparent}
    .sub{font-size:16px;color:#7c6b9e;margin-top:8px;letter-spacing:3px;text-transform:uppercase}
    .hint{font-size:13px;color:#5a4a7a;margin-top:24px}
  </style></head><body><div class="wrap">
    <div class="emoji">🔥🥂</div>
    <h1>ROAST<br>OR TOAST</h1>
    <div class="sub">someone's getting roasted either way</div>
    <div class="hint">tap GET TARGET to begin</div>
  </div></body></html>`);
});

// How it works card
registerSnapHandler(app, {
  path: "/how",
  handler: () => ({
    type: "frame",
    frame: {
      title: "How It Works",
      image: {
        src: `${SNAP_BASE}/how-card`,
        aspectRatio: "3:2"
      },
      buttons: [
        { label: "COOL LETS GO", icon: "arrow-right" }
      ],
      postUrl: `${SNAP_BASE}/get-target`
    },
    theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
  })
});

app.get("/how-card", (c) => {
  return c.html(`<!DOCTYPE html><html><head><style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:#0f0b1a;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0}
    .wrap{padding:40px;max-width:400px}
    h2{font-size:28px;font-weight:800;color:#9b87f5;margin-bottom:20px}
    .step{display:flex;align-items:flex-start;margin-bottom:16px;gap:12px}
    .num{background:#9b87f5;color:#0f0b1a;width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;flex-shrink:0}
    .txt{font-size:15px;line-height:1.4;color:#c4b5d4}
    .warn{margin-top:20px;padding:12px;background:rgba(217,70,15,0.15);border-radius:8px;font-size:13px;color:#f59e0b}
  </style></head><body><div class="wrap">
    <h2>HOW IT WORKS</h2>
    <div class="step"><div class="num">1</div><div class="txt">You get a random Farcaster profile</div></div>
    <div class="step"><div class="num">2</div><div class="txt">AI generates a <b>ruthless roast</b> AND an <b>over-embellished toast</b></div></div>
    <div class="step"><div class="num">3</div><div class="txt">You pick which one posts as a cast</div></div>
    <div class="step"><div class="num">4</div><div class="txt">Everyone gets roasted either way</div></div>
    <div class="warn">WARNING: Targets WILL see your cast</div>
  </div></body></html>`);
});

// Get a target
registerSnapHandler(app, {
  path: "/get-target",
  handler: async (ctx) => {
    const fid = ctx.message?.interactor?.fid;
    if (!fid || !NEYNAR_API_KEY) {
      return {
        type: "frame",
        frame: {
          title: "Error",
          image: { src: `${SNAP_BASE}/error-card?msg=${encodeURIComponent("Could not identify you. Open from Warpcast.")}`, aspectRatio: "3:2" },
          buttons: [{ label: "RETRY" }],
          postUrl: `${SNAP_BASE}/get-target`
        },
        theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
      };
    }

    const profile = await fetchRandomProfile(fid);
    if (!profile) {
      return {
        type: "frame",
        frame: {
          title: "No targets found",
          image: { src: `${SNAP_BASE}/error-card?msg=${encodeURIComponent("Could not find a target. Try again.")}`, aspectRatio: "3:2" },
          buttons: [{ label: "RETRY" }],
          postUrl: `${SNAP_BASE}/get-target`
        },
        theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
      };
    }

    const roast = generateRoast(profile);
    const toast = generateToast(profile);
    const pfp = safeImageUrl(profile.pfp_url, profile.username);
    const initials = getInitials(profile);
    const name = profile.display_name || profile.username;
    const bio = (profile.bio || "No bio. Even their profile gave up.").substring(0, 80);
    const followers = formatNum(profile.follower_count || 0);
    const following = formatNum(profile.following_count || 0);

    // Store target data in input for next route (stringified)
    const targetData = JSON.stringify({
      fid: profile.fid,
      username: profile.username,
      name,
      roast,
      toast
    });

    return {
      type: "frame",
      frame: {
        title: `Target: @${profile.username}`,
        image: {
          src: `${SNAP_BASE}/target-card?name=${encodeURIComponent(name)}&user=${encodeURIComponent(profile.username)}&bio=${encodeURIComponent(bio)}&followers=${followers}&following=${following}&initials=${encodeURIComponent(initials)}&pfp=${encodeURIComponent(pfp)}&roast=${encodeURIComponent(roast)}&toast=${encodeURIComponent(toast)}`,
          aspectRatio: "3:2"
        },
        buttons: [
          { label: "ROAST THEM", icon: "arrow-left" },
          { label: "TOAST THEM", icon: "arrow-right" }
        ],
        input: { text: targetData },
        postUrl: `${SNAP_BASE}/pick`
      },
      theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
    };
  }
});

// Target card — show profile + preview both roast and toast
app.get("/target-card", (c) => {
  const q = c.req.query();
  return c.html(`<!DOCTYPE html><html><head><style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:#0f0b1a;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0;padding:20px}
    .wrap{display:flex;gap:24px;width:100%;max-width:640px;align-items:stretch}
    .left{flex:0 0 180px;display:flex;flex-direction:column;align-items:center;gap:12px}
    .avatar{width:100px;height:100px;border-radius:50%;background:linear-gradient(135deg,#9b87f5,#d946ef);display:flex;align-items:center;justify-content:center;font-size:36px;font-weight:800;color:#0f0b1a;overflow:hidden}
    .avatar img{width:100%;height:100%;object-fit:cover;border-radius:50%}
    .name{font-size:20px;font-weight:800;text-align:center}
    .handle{font-size:13px;color:#7c6b9e}
    .stats{font-size:12px;color:#5a4a7a;text-align:center}
    .bio{font-size:12px;color:#9b87f5;text-align:center;font-style:italic;max-width:160px}
    .right{flex:1;display:flex;flex-direction:column;gap:12px}
    .card{padding:14px;border-radius:10px;font-size:13px;line-height:1.5;flex:1}
    .roast{background:rgba(220,38,38,0.12);border-left:3px solid #dc2626;color:#fca5a5}
    .toast{background:rgba(34,197,94,0.12);border-left:3px solid #22c55e;color:#86efac}
    .label{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;margin-bottom:6px}
    .roast .label{color:#dc2626}
    .toast .label{color:#22c55e}
    .divider{font-size:12px;color:#3d2f54;text-align:center;padding:4px 0}
  </style></head><body><div class="wrap">
    <div class="left">
      <div class="avatar"><img src="${decodeURIComponent(q.pfp || '')}" onerror="this.style.display='none';this.parentElement.textContent='${decodeURIComponent(q.initials || '?')}'" /></div>
      <div class="name">${decodeURIComponent(q.name || 'Unknown')}</div>
      <div class="handle">@${decodeURIComponent(q.user || '')}</div>
      <div class="stats">${q.followers || '?'} followers · ${q.following || '?'} following</div>
      <div class="bio">${decodeURIComponent(q.bio || '')}</div>
    </div>
    <div class="right">
      <div class="card roast">
        <div class="label">ROAST</div>
        ${decodeURIComponent(q.roast || '')}
      </div>
      <div class="divider">— OR —</div>
      <div class="card toast">
        <div class="label">TOAST</div>
        ${decodeURIComponent(q.toast || '')}
      </div>
    </div>
  </div></body></html>`);
});

// Handle pick
registerSnapHandler(app, {
  path: "/pick",
  handler: async (ctx) => {
    const input = ctx.message?.input?.text || "";
    let pick = "roast";
    let target: any = null;

    try {
      target = JSON.parse(input);
    } catch {
      // If input parse fails, use action param
      pick = "roast";
    }

    // Determine pick from button index
    const buttonIndex = ctx.message?.button?.index;
    if (buttonIndex === 1) pick = "roast";
    else if (buttonIndex === 2) pick = "toast";

    if (!target) {
      return {
        type: "frame",
        frame: {
          title: "Error",
          image: { src: `${SNAP_BASE}/error-card?msg=${encodeURIComponent("Lost the target. Try again.")}`, aspectRatio: "3:2" },
          buttons: [{ label: "RETRY" }],
          postUrl: `${SNAP_BASE}/get-target`
        },
        theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
      };
    }

    const text = pick === "roast" ? target.roast : target.toast;
    const emoji = pick === "roast" ? "🔥" : "🥂";
    const castText = `${emoji} ${text}`;

    return {
      type: "frame",
      frame: {
        title: `${emoji} ${pick.toUpperCase()} posted!`,
        image: {
          src: `${SNAP_BASE}/result-card?pick=${encodeURIComponent(pick)}&text=${encodeURIComponent(text)}&target=${encodeURIComponent(target.username)}`,
          aspectRatio: "3:2"
        },
        buttons: [
          { label: "CAST IT" },
          { label: "NEXT TARGET", icon: "arrow-right" }
        ],
        input: { text: castText },
        postUrl: `${SNAP_BASE}/cast-or-next`
      },
      theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
    };
  }
});

// Result card
app.get("/result-card", (c) => {
  const q = c.req.query();
  const isRoast = q.pick === "roast";
  const color = isRoast ? "#dc2626" : "#22c55e";
  const bgColor = isRoast ? "rgba(220,38,38,0.12)" : "rgba(34,197,94,0.12)";
  const emoji = isRoast ? "🔥" : "🥂";
  return c.html(`<!DOCTYPE html><html><head><style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:#0f0b1a;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0;padding:30px}
    .wrap{max-width:500px;text-align:center}
    .emoji{font-size:60px;margin-bottom:12px}
    h2{font-size:28px;font-weight:900;color:${color};margin-bottom:8px}
    .target{font-size:14px;color:#7c6b9e;margin-bottom:20px}
    .text{background:${bgColor};border:1px solid ${color};border-radius:12px;padding:20px;font-size:16px;line-height:1.5}
    .hint{font-size:12px;color:#5a4a7a;margin-top:16px}
  </style></head><body><div class="wrap">
    <div class="emoji">${emoji}</div>
    <h2>${isRoast ? "ROASTED" : "TOASTED"}</h2>
    <div class="target">@${decodeURIComponent(q.target || '')}</div>
    <div class="text">${decodeURIComponent(q.text || '')}</div>
    <div class="hint">tap CAST IT to post, or NEXT TARGET to go again</div>
  </div></body></html>`);
});

// Cast or next
registerSnapHandler(app, {
  path: "/cast-or-next",
  handler: async (ctx) => {
    const buttonIndex = ctx.message?.button?.index;

    if (buttonIndex === 1) {
      // Cast it — use compose action
      const castText = ctx.message?.input?.text || "";
      return {
        type: "frame",
        frame: {
          title: "Post your roast/toast",
          buttons: [{ label: "POST IT" }],
          input: { text: castText },
          postUrl: `${SNAP_BASE}/get-target`
        },
        action: {
          type: "compose",
          cast: { text: castText }
        },
        theme: { accent: "#9b87f5", background: "#0f0b1a", foreground: "#e8e0f0" }
      };
    } else {
      // Next target
      return {
        type: "redirect",
        to: `${SNAP_BASE}/get-target`
      };
    }
  }
});

// Error card
app.get("/error-card", (c) => {
  const msg = c.req.query("msg") || "Something went wrong";
  return c.html(`<!DOCTYPE html><html><head><style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{background:#0f0b1a;display:flex;align-items:center;justify-content:center;height:100vh;font-family:system-ui;color:#e8e0f0}
    .wrap{text-align:center}
    .emoji{font-size:50px;margin-bottom:12px}
    h2{font-size:22px;color:#dc2626;margin-bottom:8px}
    p{font-size:14px;color:#7c6b9e}
  </style></head><body><div class="wrap">
    <div class="emoji">😵</div>
    <h2>OOPS</h2>
    <p>${decodeURIComponent(msg)}</p>
  </div></body></html>`);
});

export default app;
"}

